public class Animal {
    protected String nome;

    public Animal(String nome) {
        this.nome = nome;
    }

    public void dormir() {
        System.out.println(nome + " está dormindo");
    }
}

public class Cachorro extends Animal {
    public Cachorro(String nome) {
        super(nome); // chama o construtor de Animal — obrigatório se Animal não tem construtor vazio
    }

    public void latir() {
        System.out.println(nome + " au au!"); // 'nome' herdado de Animal
    }
}

public abstract class Animal {
    public abstract String falar();
}

public class Cachorro extends Animal {
    @Override
    public String falar() { return "Au au!"; }
}

public class Gato extends Animal {
    @Override
    public String falar() { return "Miau!"; }
}

public class Zoologico {
    public static void main(String[] args) {
        List<Animal> animais = List.of(new Cachorro(), new Gato());

        for (Animal animal : animais) {
            // o tipo da variável é Animal, mas o método executado depende
            // do tipo REAL do objeto em runtime — isso é polimorfismo
            System.out.println(animal.falar());
        }
    }
}

// O código de negócio depende só da abstração (interface), não da implementação concreta
public interface NotificadorService {
    void enviar(String destinatario, String mensagem);
}

public class EmailNotificador implements NotificadorService {
    @Override
    public void enviar(String destinatario, String mensagem) {
        System.out.println("Enviando e-mail para " + destinatario);
    }
}

public class PedidoService {
    private final NotificadorService notificador; // depende da abstração

    public PedidoService(NotificadorService notificador) {
        this.notificador = notificador; // pode ser Email, SMS, Push — o service não sabe nem precisa saber
    }

    public void confirmarPedido(String cliente) {
        notificador.enviar(cliente, "Pedido confirmado!");
    }
}

// Interface: contrato de capacidade — Cachorro e Robo não têm relação de herança
public interface Correvel {
    void correr();

    default void parar() { // default method: implementação compartilhada, opcional de sobrescrever
        System.out.println("Parando...");
    }
}

// Classe abstrata: relação IS-A real, com estado compartilhado
public abstract class Animal {
    protected String nome; // estado — interface não pode ter isso

    public Animal(String nome) { this.nome = nome; }

    public abstract String emitirSom(); // contrato que cada filha implementa do seu jeito

    public void dormir() { // método concreto, compartilhado por todas as filhas
        System.out.println(nome + " dormindo");
    }
}

public class Cachorro extends Animal implements Correvel {
    public Cachorro(String nome) { super(nome); }

    @Override
    public String emitirSom() { return "Au au"; }

    @Override
    public void correr() { System.out.println(nome + " correndo"); }
}
